// ========================= 录音按钮: 模拟语音转文字 (任意键盘按下 / 发送按钮 / 点击输入框 均停止录音) =========================
(function initVoiceButton() {
    const voiceBtn = document.getElementById("voiceBtn");
    const textarea = document.getElementById("chatInput");
    const sendButton = document.getElementById("sendButton");
    if (!voiceBtn || !textarea || !sendButton) return;
    
    let isRecording = false;
    let recordingInterval = null;
    let globalKeydownHandler = null;
    const originalSvgHtml = voiceBtn.innerHTML;
    
    // 模拟语音识别的词库（无空格分隔，直接拼接）
    const voiceWords = [
        "你好", "我在听", "语音识别", "模拟文本", "继续输入", 
        "你好吗", "今天天气不错", "这是一段测试", "录音中", 
        "请说", "消息内容", "实时转写", "语音助手"
    ];
    let wordIndex = 0;
    
    function createColoredGif() {
        const img = document.createElement("img");
        img.src = "data:image/gif;base64,";
        img.alt = "recording";
        img.className = "voice-gif";
        img.style.width = "19px";
        img.style.height = "19px";
        img.style.display = "block";
        img.style.pointerEvents = "none";
        return img;
    }
    
    function appendVoiceText() {
        if (!isRecording) return;
        const word = voiceWords[wordIndex % voiceWords.length];
        wordIndex++;
        const currentValue = textarea.value;
        const newValue = currentValue + word;  // 直接拼接，不加空格
        textarea.value = newValue;
        const inputEvent = new Event('input', { bubbles: true });
        textarea.dispatchEvent(inputEvent);
        textarea.scrollTop = textarea.scrollHeight;
    }
    
    function stopRecording() {
        if (!isRecording) return;
        isRecording = false;
        if (recordingInterval) {
            clearInterval(recordingInterval);
            recordingInterval = null;
        }
        if (globalKeydownHandler) {
            document.removeEventListener('keydown', globalKeydownHandler);
            globalKeydownHandler = null;
        }
        voiceBtn.innerHTML = originalSvgHtml;
        wordIndex = 0;
    }
    
    function startRecording() {
        if (isRecording) return;
        if (recordingInterval) clearInterval(recordingInterval);
        isRecording = true;
        wordIndex = 0;
        const gifImg = createColoredGif();
        voiceBtn.innerHTML = '';
        voiceBtn.appendChild(gifImg);
        recordingInterval = setInterval(() => {
            appendVoiceText();
        }, 400);
        
        // 全局监听任意键盘按键，按下即停止录音
        if (!globalKeydownHandler) {
            globalKeydownHandler = function(e) {
                // 忽略仅修饰键（如Ctrl, Alt, Shift）单独按下？但需求任意键，包括修饰键也应该停止，更符合直觉
                // 为了不干扰输入体验，直接停止录音即可，不做过滤
                if (isRecording) {
                    stopRecording();
                }
            };
            document.addEventListener('keydown', globalKeydownHandler);
        }
    }
    
    // 点击录音按钮：切换
    voiceBtn.addEventListener('click', function(e) {
        e.stopPropagation();
        if (isRecording) {
            stopRecording();
        } else {
            startRecording();
        }
    });
    
    // 点击输入框内部停止录音（用户点击文本区）
    textarea.addEventListener('click', function(e) {
        if (isRecording) {
            stopRecording();
        }
    });
    
    // 点击发送按钮停止录音（先停录音，再执行原有发送逻辑，不干扰原有功能）
    sendButton.addEventListener('click', function(e) {
        if (isRecording) {
            stopRecording();
        }
        // 原有发送逻辑已在其他地方绑定，此处不需要重复执行，避免重复。
        // 注意：原有 sendButton 的 click 监听器已在上方文本框核心中定义，会执行发送消息/清空等操作。
        // 这里只负责停止录音，原有逻辑会正常执行。
    });
})();
